INSERT INTO `memory_entry`
(`title`, `summary`, `content`, `memory_date`, `cover_image_url`, `cover_storage_path`, `mood_tags`, `is_featured`, `visibility`, `sort_order`, `favorite_count`)
VALUES
('溪边慢下来的下午','她坐在溪边石头上，水声很轻，像把那天的时间也一点点放慢了。','溪边那天下午没有很大的事情发生，只是风从树影里穿过去，水声一直很轻。\n\n她坐在石头上时没有急着看镜头，裙摆垂下来一点，整个人像被周围的绿色慢慢包住。后来又坐到水边长椅上，低头的那一瞬间很安静，好像心里的事也被溪水带轻了一点。\n\n我喜欢这种没有剧情却很真实的日子。它不需要特别热闹，只要她在旁边，水边的光、长椅和风声都会变成可以记住的东西。','2026-06-17','/uploads/photos/133_小可_溪边石头坐姿照.png','photos/133_小可_溪边石头坐姿照.png','溪边,慢时光,安静',1,'PUBLIC',220,NULL),
('楼梯间那盏夜色','绿色裙子站在楼梯间的灯下，夜晚忽然变得很柔，像一声轻轻的晚安。','楼梯间的灯不算亮，周围也没有特别漂亮的布景。\n\n可是她穿着绿色裙子站在那里时，普通的楼梯间忽然像有了故事。她没有摆出很热烈的表情，只是安安静静看向镜头，夜色压下来一点，反而把那份清冷衬得更柔。\n\n后来再看到这组照片，会想到一些很细的片段。也许只是出门前后的一小会儿，也许只是路过楼梯时随手拍下，但她站在那里，像把晚上的安静留成了一页手账。','2026-06-17','/uploads/photos/137_小可_夜晚楼梯间绿色裙装全身照.png','photos/137_小可_夜晚楼梯间绿色裙装全身照.png','夜晚,楼梯间,温柔',1,'PUBLIC',230,NULL),
('窗边白裙和一点光','白裙站在窗边的时候，光把她照得很轻，像一封慢慢展开的夏日信。','窗边的光总是很适合小可。\n\n她穿着白裙站在那里，整个人安静得像一页没有写完的日记。彩墙、窗光和裙摆都很轻，轻到不需要多说什么，照片自己就已经有了温度。\n\n这几张放在一起，会让人想起她不说话时的样子。不是疏离，而是把情绪收得很稳，只在光线落下来的地方，悄悄露出一点柔软。','2026-06-18','/uploads/photos/138_小可_白裙窗边站姿照.png','photos/138_小可_白裙窗边站姿照.png','窗边,白裙,夏日',1,'PUBLIC',240,NULL),
('船上的风把傍晚吹慢','她穿着藏蓝裙子站在船上，风从身边经过，把傍晚也吹得慢了下来。','船上那天有风，远处的光也慢慢暗下来。\n\n她穿着藏蓝色连衣裙站在那里，裙摆被风轻轻带起，整个人看起来很稳。不是刻意的漂亮，而是那种被傍晚托住的安静，让人会想多看一会儿。\n\n我把这组照片放进手账，是因为它很像一段被放慢的路程。船往前走，风也往前走，可她站在画面里，好像把那个傍晚留了下来。','2026-06-18','/uploads/photos/142_小可_船上藏蓝连衣裙站姿照.png','photos/142_小可_船上藏蓝连衣裙站姿照.png','船上,傍晚,藏蓝裙',1,'PUBLIC',250,NULL),
('后台换装前的安静','她站在后台整理好状态，白上衣和黑裙很简单，却有一种准备走进灯光前的认真。','后台通常有一点忙，也有一点乱。\n\n她站在那里的时候，白上衣和黑裙都很简单，反而更能看见她自己的气质。像是还没真正走到人群前，先在一个安静角落里把状态收好。\n\n这类照片不是舞台上最热烈的一刻，却很值得记。因为它记录的是她进入光亮之前的那几秒，平静、认真，也有一点只属于自己的小紧张。','2026-06-18','/uploads/photos/143_小可_后台白上衣黑裙全身照.png','photos/143_小可_后台白上衣黑裙全身照.png','后台,准备,认真',0,'PUBLIC',260,NULL),
('泳池边的夏天','水光很亮，她站在泳池边回头看过来，像把整个夏天都轻轻递给了镜头。','泳池边这一组很适合放在一起看。\n\n水光一直在晃，她一会儿靠近镜头，一会儿坐在池边看向别处，白衫被阳光照得很轻。她平时身上那点清冷，在这种明亮的夏天里被软化了不少，整个人看起来松弛，也很鲜活。\n\n最喜欢的是回眸那一张。那一下很短，却像把阳光、水声和她当天的好心情都收住了。以后翻到这一页，会很容易想起：原来这个夏天也曾这样亮过。','2026-06-20','/uploads/photos/166_小可_泳池边白衫连体泳装全身照.png','photos/166_小可_泳池边白衫连体泳装全身照.png','泳池,夏天,松弛',1,'PUBLIC',270,NULL),
('抱着玩偶的安静夜晚','她抱着玩偶坐在卧室里，白裙铺开一点，连夜晚都变得软软的。','卧室里的照片总是会比外面的更柔一点。\n\n她抱着玩偶坐在那里，白裙铺开，表情也比平时放松。没有舞台，没有人群，也没有需要努力维持的状态，只是很普通地待在房间里，却让人觉得这一天终于安稳落地了。\n\n我想把这张留在手账里，是因为它不像一张刻意展示的照片，更像一个被允许靠近的小瞬间。她把疲惫放下，也把柔软留下。','2026-06-21','/uploads/photos/173_小可_卧室白裙抱玩偶坐姿照.png','photos/173_小可_卧室白裙抱玩偶坐姿照.png','卧室,玩偶,安稳',1,'PUBLIC',280,NULL),
('健身房里认真变好的日子','她在健身房里比了个心，认真训练之后的小甜意，就这样被留在了镜子前。','健身房这一组很有生活感。\n\n她会认真看镜子里的状态，也会坐下来休息一会儿，粉色瑜伽裤、蓝灰运动装、镜前自拍，每一张都像在记录她一点点照顾自己的过程。小可不是很张扬的人，所以这种认真反而特别好看。\n\n最后那张比心很可爱。像是训练结束后忽然给今天盖了一个小印章，告诉自己也告诉镜头：今天也有好好生活，今天也值得被喜欢。','2026-06-21','/uploads/photos/181_小可_健身房比心站姿照.png','photos/181_小可_健身房比心站姿照.png','健身房,认真,可爱',1,'PUBLIC',290,NULL);
